  const sym=o._sym||'$';const code=o._curCode||'';
  const setV=(id,v)=>{const el=document.getElementById(id);if(el)el.textContent=v;};
  const setH=(id,v)=>{const el=document.getElementById(id);if(el)el.innerHTML=v;};
