const __mkbdSelected={day:null,month:null,year:null};
function __mkbdFilterOrders(sel){return (orders||[]).filter(o=>{const c=o._createdAt;if(!c)return false;if(sel.day&&__mkbdDays[c.getDay()]!==sel.day)return false;if(sel.month&&__mkbdMonths[c.getMonth()]!==sel.month)return false;if(sel.year&&String(c.getFullYear())!==sel.year)return false;return true;});}
function __mkbdGenerateData(sel){const cur=window.__lateenWalletCur;const list=(!sel.day&&!sel.month&&!sel.year)?(orders||[]):__mkbdFilterOrders(sel);let earnings=0,pieces=0,succeeded=0,failed=0;list.forEach(o=>{const status=o._status||'pending';if(status==='delivered'){if(!cur||(o._curCode||'USD')===cur)earnings+=(o.commPerUnit||0)*(o.qty||0);pieces+=(o.qty||0);succeeded++;}if(status==='cancelled')failed++;});return{earnings,pieces,succeeded,failed};}
function __ordFrac(n){if(n===1)return'طلبيه واحده';if(n===2)return'طلبيتين';return n+' طلبيات';}
function mkbdRenderBreakdown(){const grid=document.getElementById('mkbd-grid');if(!grid)return;const data=__mkbdGenerateData(__mkbdSelected);const total=data.succeeded+data.failed;const succPct=total>0?Math.round((data.succeeded/total)*100):0;const failPct=total>0?Math.round((data.failed/total)*100):0;const sym=(typeof window.__lateenSelSym==='function')?window.__lateenSelSym():'$';const ar=__ar();const succLbl=ar?'الطلبات تم تسليمها':'Succeeded';const failLbl=ar?'الطلبات لم يتم تسليمها':'Failed';const succSub=ar?('من أصل '+__ordFrac(total)):(succPct+'%');const failSub=ar?('من أصل '+__ordFrac(total)):(failPct+'%');const netLbl=ar?'صافي الأرباح منذ إنشاء الحساب':'Net earnings';const piecesLbl=ar?'قطع تم بيعها':'Pieces sold';grid.innerHTML=`
    <div class="mkbd-box"><div class="mkbd-box-label" data-no-i18n>${netLbl}</div><div class="mkbd-box-value">${__money(data.earnings,sym,window.__lateenWalletCur)}</div></div>
    <div class="mkbd-box"><div class="mkbd-box-label" data-no-i18n>${piecesLbl}</div><div class="mkbd-box-value">${data.pieces}</div></div>
    <div class="mkbd-box"><div class="mkbd-box-label" data-no-i18n>${succLbl}</div><div class="mkbd-box-value green" data-no-i18n>${data.succeeded} <span style="font-size:12px;color:var(--color-text-tertiary);font-weight:500;">(${succSub})</span></div></div>
    <div class="mkbd-box"><div class="mkbd-box-label" data-no-i18n>${failLbl}</div><div class="mkbd-box-value red" data-no-i18n>${data.failed} <span style="font-size:12px;color:var(--color-text-tertiary);font-weight:500;">(${failSub})</span></div></div>
  `;}
const __mkbdRangeMeta={daily:{key:'day',defaultLabel:'Day',list:null},monthly:{key:'month',defaultLabel:'Month',list:null},yearly:{key:'year',defaultLabel:'Year',list:null}};
function __mkbdUpdateTabLabel(filterKey){const rangeName=Object.keys(__mkbdRangeMeta).find(r=>__mkbdRangeMeta[r].key===filterKey);const tab=document.querySelector(`.mkbd-range-tab[data-range="${rangeName}"]`);if(!tab)return;const val=__mkbdSelected[filterKey];tab.innerHTML=(val?val:__mkbdRangeMeta[rangeName].defaultLabel)+' <span class="mkbd-chev-sm">▾</span>';tab.classList.toggle('active',!!val);__mkbdUpdateAllTabState();}
function __mkbdUpdateAllTabState(){const allTab=document.querySelector('.mkbd-range-tab[data-range="all"]');if(!allTab)return;const anySelected=__mkbdSelected.day||__mkbdSelected.month||__mkbdSelected.year;allTab.classList.toggle('active',!anySelected);}
function __mkbdCloseDropdown(rangeName){const meta=__mkbdRangeMeta[rangeName];if(!meta||!meta.list)return;meta.list.classList.remove('open');const tab=document.querySelector(`.mkbd-range-tab[data-range="${rangeName}"]`);if(tab)tab.classList.remove('open');}
function __mkbdCloseAllDropdowns(){Object.keys(__mkbdRangeMeta).forEach(r=>__mkbdCloseDropdown(r));}
function __mkbdBuildDropdown(listEl,keys,filterKey,rangeName){if(!listEl)return;listEl.innerHTML='';const clearItem=document.createElement('div');clearItem.className='mkbd-dd-item clear';clearItem.textContent='Clear selection';clearItem.addEventListener('click',e=>{e.stopPropagation();__mkbdSelected[filterKey]=null;__mkbdUpdateTabLabel(filterKey);__mkbdCloseDropdown(rangeName);mkbdRenderBreakdown();});listEl.appendChild(clearItem);keys.forEach(key=>{const item=document.createElement('div');item.className='mkbd-dd-item';item.textContent=key;item.addEventListener('click',e=>{e.stopPropagation();__mkbdSelected[filterKey]=key;__mkbdUpdateTabLabel(filterKey);__mkbdCloseDropdown(rangeName);mkbdRenderBreakdown();});listEl.appendChild(item);});}
function mkbdTabClick(range,tabEl){if(range==='all'){__mkbdCloseAllDropdowns();__mkbdSelected.day=null;__mkbdSelected.month=null;__mkbdSelected.year=null;Object.keys(__mkbdRangeMeta).forEach(r=>{const t=document.querySelector(`.mkbd-range-tab[data-range="${r}"]`);if(t){t.innerHTML=__mkbdRangeMeta[r].defaultLabel+' <span class="mkbd-chev-sm">▾</span>';t.classList.remove('active');}});tabEl.classList.add('active');mkbdRenderBreakdown();return;}const meta=__mkbdRangeMeta[range];if(!meta||!meta.list)return;const isOpen=meta.list.classList.contains('open');Object.keys(__mkbdRangeMeta).forEach(r=>{if(r!==range)__mkbdCloseDropdown(r);});if(isOpen){__mkbdCloseDropdown(range);}else{meta.list.classList.add('open');tabEl.classList.add('open');}}
function mkbdToggleOpen(){const toggle=document.getElementById('mkbdToggle');const wrap=document.getElementById('mkbdWrap');if(!toggle||!wrap)return;const isOpen=wrap.classList.toggle('open');toggle.classList.toggle('open',isOpen);}
function __mkbdInit(){__mkbdRangeMeta.daily.list=document.getElementById('mkbd-daily-list');__mkbdRangeMeta.monthly.list=document.getElementById('mkbd-monthly-list');__mkbdRangeMeta.yearly.list=document.getElementById('mkbd-yearly-list');if(!__mkbdRangeMeta.daily.list)return;const curYear=new Date().getFullYear();const yrs=[curYear-2,curYear-1,curYear].map(String);__mkbdBuildDropdown(__mkbdRangeMeta.daily.list,__mkbdDays,'day','daily');__mkbdBuildDropdown(__mkbdRangeMeta.monthly.list,__mkbdMonths,'month','monthly');__mkbdBuildDropdown(__mkbdRangeMeta.yearly.list,yrs,'year','yearly');document.addEventListener('click',e=>{if(!e.target.closest('.mkbd-range-tab')&&!e.target.closest('.mkbd-dropdown-list'))__mkbdCloseAllDropdowns();});mkbdRenderBreakdown();}
__mkbdInit();

